require('dotenv').config();
const express = require('express');
const cors = require('cors');
const helmet = require('helmet');
const swaggerUi = require('swagger-ui-express');
const swaggerSpec = require('./config/swagger');

// Route imports
const authRoutes = require('./routes/auth');
const userRoutes = require('./routes/users');
const roleRoutes = require('./routes/roles');
const shopRoutes = require('./routes/shops');
const rotaRoutes = require('./routes/rotas');
const attendanceRoutes = require('./routes/attendance');
const inventoryItemRoutes = require('./routes/inventoryItems');
const inventoryQueryRoutes = require('./routes/inventoryQueries');
const { sendSuccess } = require('./utils/response');
const { notFoundHandler, globalErrorHandler } = require('./middleware/errorHandler');

const app = express();

// Security & parsing middleware
// contentSecurityPolicy disabled — Swagger UI uses inline scripts that CSP blocks
app.use(helmet({ contentSecurityPolicy: false }));
app.use(cors());
app.use(express.json());

// Health check
app.get('/health', (req, res) => sendSuccess(res, 'Service is healthy', {
  timestamp: new Date().toISOString(),
}));

// Swagger UI — http://localhost:5000/api-docs
app.use('/api-docs', swaggerUi.serve, swaggerUi.setup(swaggerSpec, {
  customSiteTitle: 'Staff & Inventory API Docs',
  swaggerOptions: { persistAuthorization: true },
}));
// Raw OpenAPI JSON — useful for Postman import
app.get('/api-docs.json', (req, res) => sendSuccess(res, 'OpenAPI spec fetched', swaggerSpec));

// API routes
app.use('/api/auth', authRoutes);
app.use('/api/users', userRoutes);
app.use('/api/roles', roleRoutes);
app.use('/api/shops', shopRoutes);
app.use('/api/rotas', rotaRoutes);
app.use('/api/attendance', attendanceRoutes);
app.use('/api/inventory/items', inventoryItemRoutes);
app.use('/api/inventory/queries', inventoryQueryRoutes);

// 404 + global error handlers
app.use(notFoundHandler);
app.use(globalErrorHandler);


module.exports = app;

require('dotenv').config();
const express = require('express');
const cors = require('cors');
const helmet = require('helmet');
const swaggerUi = require('swagger-ui-express');
const swaggerSpec = require('./config/swagger');

// Route imports
const authRoutes = require('./routes/auth');
const userRoutes = require('./routes/users');
const roleRoutes = require('./routes/roles');
const shopRoutes = require('./routes/shops');
const rotaRoutes = require('./routes/rotas');
const attendanceRoutes = require('./routes/attendance');
const inventoryItemRoutes = require('./routes/inventoryItems');
const inventoryQueryRoutes = require('./routes/inventoryQueries');
const observabilityRoutes = require('./routes/observability');
const { sendSuccess } = require('./utils/response');
const { notFoundHandler, globalErrorHandler } = require('./middleware/errorHandler');
const { requestAnalytics } = require('./middleware/requestAnalyticsMiddleware');

const app = express();

// Security & parsing middleware
// contentSecurityPolicy disabled — Swagger UI uses inline scripts that CSP blocks
app.use(helmet({ contentSecurityPolicy: false }));
app.use(cors());
app.use(express.json());
app.use(requestAnalytics);

// Health check
app.get('/health', (req, res) => sendSuccess(res, 'Service is healthy', {
  timestamp: new Date().toISOString(),
}));

// Swagger UI — http://localhost:5000/api-docs
app.use('/api-docs', swaggerUi.serve, swaggerUi.setup(swaggerSpec, {
  customSiteTitle: 'Staff & Inventory API Docs',
  swaggerOptions: { persistAuthorization: true },
}));
// Raw OpenAPI JSON — useful for Postman import
app.get('/api-docs.json', (req, res) => sendSuccess(res, 'OpenAPI spec fetched', swaggerSpec));

// API routes
app.use('/api/auth', authRoutes);
app.use('/api/users', userRoutes);
app.use('/api/roles', roleRoutes);
app.use('/api/shops', shopRoutes);
app.use('/api/rotas', rotaRoutes);
app.use('/api/attendance', attendanceRoutes);
app.use('/api/inventory/items', inventoryItemRoutes);
app.use('/api/inventory/queries', inventoryQueryRoutes);
app.use('/api/observability', observabilityRoutes);

// 404 + global error handlers
app.use(notFoundHandler);
app.use(globalErrorHandler);


module.exports = app;

const jwt = require('jsonwebtoken');
const User = require('../models/User');
const AppError = require('../utils/AppError');
const asyncHandler = require('../utils/asyncHandler');
const { sendSuccess } = require('../utils/response');

// Generate JWT
const generateToken = (id) =>
  jwt.sign({ id }, process.env.JWT_SECRET, { expiresIn: process.env.JWT_EXPIRES_IN });

// @route  POST /api/auth/login
// @access Public
const login = asyncHandler(async (req, res) => {
  const { email, password } = req.body;

  if (!email || !password) {
    throw new AppError('Email and password are required', 400);
  }

  const user = await User.findOne({ email, is_active: true })
    .select('+password_hash')
    .populate('role_id');

  if (!user || !(await user.matchPassword(password))) {
    throw new AppError('Invalid credentials', 400);
  }

  return sendSuccess(res, 'Login successful', {
    token: generateToken(user._id),
    must_change_password: user.must_change_password,
    user: {
      id: user._id,
      name: user.name,
      email: user.email,
      role: user.role_id,
      shop_id: user.shop_id,
    },
  });
});

module.exports = { login };

const jwt = require('jsonwebtoken');
const User = require('../models/User');
const AppError = require('../utils/AppError');
const asyncHandler = require('../utils/asyncHandler');
const { sendSuccess } = require('../utils/response');

// Generate JWT
const generateToken = (id) =>
  jwt.sign({ id }, process.env.JWT_SECRET, { expiresIn: process.env.JWT_EXPIRES_IN });

// @route  POST /api/auth/login
// @access Public
const login = asyncHandler(async (req, res) => {
  const { email, password } = req.body;

  if (!email || !password) {
    throw new AppError('Email and password are required', 400);
  }

  const user = await User.findOne({ email })
    .select('+password_hash')
    .populate('role_id');

  if (!user || !(await user.matchPassword(password))) {
    throw new AppError('Invalid credentials', 400);
  }

  if (!user.is_active) {
    throw new AppError('User not found or deactivated', 400);
  }

  return sendSuccess(res, 'Login successful', {
    token: generateToken(user._id),
    must_change_password: user.must_change_password,
    user: {
      id: user._id,
      name: user.name,
      email: user.email,
      role: user.role_id,
      active_shop_id: user.active_shop_id || user.shop_id || null,
      shop_id: user.shop_id,
      assigned_shop_ids: user.assigned_shop_ids || [],
    },
  });
});

module.exports = { login };

const InventoryItem = require('../models/InventoryItem');
const AppError = require('../utils/AppError');
const asyncHandler = require('../utils/asyncHandler');
const { sendSuccess } = require('../utils/response');

// GET /api/inventory/items
const getItems = asyncHandler(async (req, res) => {
  const filter = {};
  if (req.query.shop_id) filter.shop_id = req.query.shop_id;
  if (req.query.status) filter.status = req.query.status;

  const items = await InventoryItem.find(filter).populate('shop_id', 'name');
  return sendSuccess(res, 'Inventory items fetched successfully', {
    count: items.length,
    items,
  });
});

// GET /api/inventory/items/:id
const getItem = asyncHandler(async (req, res) => {
  const item = await InventoryItem.findById(req.params.id).populate('shop_id', 'name');
  if (!item) throw new AppError('Item not found', 404);
  return sendSuccess(res, 'Inventory item fetched successfully', { item });
});

// POST /api/inventory/items
const createItem = asyncHandler(async (req, res) => {
  const item = await InventoryItem.create(req.body);
  return sendSuccess(res, 'Inventory item created successfully', { item }, 201);
});

// PUT /api/inventory/items/:id
const updateItem = asyncHandler(async (req, res) => {
  const item = await InventoryItem.findByIdAndUpdate(req.params.id, req.body, {
    new: true, runValidators: true,
  });
  if (!item) throw new AppError('Item not found', 404);
  return sendSuccess(res, 'Inventory item updated successfully', { item });
});

// DELETE /api/inventory/items/:id
const deleteItem = asyncHandler(async (req, res) => {
  const item = await InventoryItem.findByIdAndDelete(req.params.id);
  if (!item) throw new AppError('Item not found', 404);
  return sendSuccess(res, 'Inventory item deleted', { item });
});

module.exports = { getItems, getItem, createItem, updateItem, deleteItem };

const InventoryItem = require('../models/InventoryItem');
const AppError = require('../utils/AppError');
const asyncHandler = require('../utils/asyncHandler');
const { sendSuccess } = require('../utils/response');
const { buildShopScope, isShopAllowed } = require('../middleware/shopScopeMiddleware');

function buildInventoryScope(user) {
  const permissions = user?.role_id?.permissions || {};
  if (permissions.can_manage_shops || permissions.can_manage_roles) {
    return { all: true, ids: [] };
  }
  return buildShopScope(user);
}

function applyInventoryScopeFilter(filter, scope) {
  if (scope.all) return;
  if (!scope.ids.length) {
    filter.shop_id = { $in: [] };
    return;
  }
  filter.shop_id = { $in: scope.ids };
}

function assertInventoryShopAllowed(scope, shopId) {
  if (scope.all) return;
  if (!isShopAllowed(scope, shopId)) {
    throw new AppError('Forbidden: shop is outside your assigned scope', 403);
  }
}

// GET /api/inventory/items
const getItems = asyncHandler(async (req, res) => {
  const scope = buildInventoryScope(req.user);
  const filter = {};
  applyInventoryScopeFilter(filter, scope);

  if (req.query.shop_id) filter.shop_id = req.query.shop_id;
  if (req.query.shop_id && !scope.all && !isShopAllowed(scope, req.query.shop_id)) {
    return sendSuccess(res, 'Inventory items fetched successfully', {
      count: 0,
      items: [],
    });
  }
  if (req.query.status) filter.status = req.query.status;

  const items = await InventoryItem.find(filter).populate('shop_id', 'name');
  return sendSuccess(res, 'Inventory items fetched successfully', {
    count: items.length,
    items,
  });
});

// GET /api/inventory/items/:id
const getItem = asyncHandler(async (req, res) => {
  const scope = buildInventoryScope(req.user);
  const filter = { _id: req.params.id };
  applyInventoryScopeFilter(filter, scope);

  const item = await InventoryItem.findOne(filter).populate('shop_id', 'name');
  if (!item) throw new AppError('Item not found', 404);
  return sendSuccess(res, 'Inventory item fetched successfully', { item });
});

// POST /api/inventory/items
const createItem = asyncHandler(async (req, res) => {
  const scope = buildInventoryScope(req.user);
  assertInventoryShopAllowed(scope, req.body.shop_id);

  const item = await InventoryItem.create(req.body);
  return sendSuccess(res, 'Inventory item created successfully', { item }, 201);
});

// PUT /api/inventory/items/:id
const updateItem = asyncHandler(async (req, res) => {
  const scope = buildInventoryScope(req.user);
  const existing = await InventoryItem.findById(req.params.id);
  if (!existing) throw new AppError('Item not found', 404);
  assertInventoryShopAllowed(scope, existing.shop_id);
  if (req.body.shop_id) assertInventoryShopAllowed(scope, req.body.shop_id);

  const item = await InventoryItem.findByIdAndUpdate(req.params.id, req.body, {
    new: true, runValidators: true,
  });
  if (!item) throw new AppError('Item not found', 404);
  return sendSuccess(res, 'Inventory item updated successfully', { item });
});

// DELETE /api/inventory/items/:id
const deleteItem = asyncHandler(async (req, res) => {
  const scope = buildInventoryScope(req.user);
  const existing = await InventoryItem.findById(req.params.id);
  if (!existing) throw new AppError('Item not found', 404);
  assertInventoryShopAllowed(scope, existing.shop_id);

  const item = await InventoryItem.findByIdAndDelete(req.params.id);
  if (!item) throw new AppError('Item not found', 404);
  return sendSuccess(res, 'Inventory item deleted', { item });
});

module.exports = { getItems, getItem, createItem, updateItem, deleteItem };

const InventoryQuery = require('../models/InventoryQuery');
const InventoryItem = require('../models/InventoryItem');
const AppError = require('../utils/AppError');
const asyncHandler = require('../utils/asyncHandler');
const { sendSuccess } = require('../utils/response');

// GET /api/inventory/queries
const getQueries = asyncHandler(async (req, res) => {
  const filter = {};
  if (req.query.shop_id) filter.shop_id = req.query.shop_id;
  if (req.query.status) filter.status = req.query.status;
  if (req.query.item_id) filter.item_id = req.query.item_id;

  const queries = await InventoryQuery.find(filter)
    .populate('item_id', 'item_name status')
    .populate('shop_id', 'name')
    .populate('reported_by', 'name email')
    .populate('resolved_by', 'name email')
    .sort({ createdAt: -1 });

  return sendSuccess(res, 'Inventory queries fetched successfully', {
    count: queries.length,
    queries,
  });
});

// GET /api/inventory/queries/:id
const getQuery = asyncHandler(async (req, res) => {
  const query = await InventoryQuery.findById(req.params.id)
    .populate('item_id', 'item_name status')
    .populate('shop_id', 'name')
    .populate('reported_by', 'name email')
    .populate('resolved_by', 'name email');

  if (!query) throw new AppError('Query not found', 404);
  return sendSuccess(res, 'Inventory query fetched successfully', { query });
});

// POST /api/inventory/queries
// Creates the query ticket + auto-sets item status to 'Damaged'
const createQuery = asyncHandler(async (req, res) => {
  const { item_id, shop_id, issue_note } = req.body;

    // Verify item exists
  const item = await InventoryItem.findById(item_id);
  if (!item) throw new AppError('Inventory item not found', 404);

    // Create the query (ticket)
  const query = await InventoryQuery.create({
    item_id,
    shop_id: shop_id || item.shop_id,
    reported_by: req.user._id,
    issue_note,
    status: 'Open',
  });

    // ── Auto-sync: set item status to 'Damaged' ──
  item.status = 'Damaged';
  await item.save();

  const populated = await query.populate([
    { path: 'item_id', select: 'item_name status' },
    { path: 'shop_id', select: 'name' },
    { path: 'reported_by', select: 'name email' },
  ]);

  return sendSuccess(res, 'Query opened and item marked as Damaged', {
    query: populated,
  }, 201);
});

// PUT /api/inventory/queries/:id/close
// Closes the query + auto-reverts item status to 'Good'
const closeQuery = asyncHandler(async (req, res) => {
  const { repair_cost, resolve_note } = req.body;

  const query = await InventoryQuery.findById(req.params.id);
  if (!query) throw new AppError('Query not found', 404);

  if (query.status === 'Closed') {
    throw new AppError('Query is already closed', 400);
  }

    // Update the query
  query.status = 'Closed';
  query.repair_cost = repair_cost ?? null;
  query.resolve_note = resolve_note ?? null;
  query.resolved_by = req.user._id;
  query.resolved_at = new Date();
  await query.save();

    // ── Auto-sync: revert item status to 'Good' ──
  await InventoryItem.findByIdAndUpdate(query.item_id, { status: 'Good' });

  const populated = await query.populate([
    { path: 'item_id', select: 'item_name status' },
    { path: 'resolved_by', select: 'name email' },
  ]);

  return sendSuccess(res, 'Query closed and item status reverted to Good', {
    query: populated,
  });
});

module.exports = { getQueries, getQuery, createQuery, closeQuery };

const InventoryQuery = require('../models/InventoryQuery');
const InventoryItem = require('../models/InventoryItem');
const AppError = require('../utils/AppError');
const asyncHandler = require('../utils/asyncHandler');
const { sendSuccess } = require('../utils/response');
const { buildShopScope, isShopAllowed } = require('../middleware/shopScopeMiddleware');

function buildInventoryScope(user) {
  const permissions = user?.role_id?.permissions || {};
  if (permissions.can_manage_shops || permissions.can_manage_roles) {
    return { all: true, ids: [] };
  }
  return buildShopScope(user);
}

function applyScopeFilter(filter, scope) {
  if (scope.all) return;
  if (!scope.ids.length) {
    filter.shop_id = { $in: [] };
    return;
  }
  filter.shop_id = { $in: scope.ids };
}

function assertShopAllowed(scope, shopId) {
  if (scope.all) return;
  if (!isShopAllowed(scope, shopId)) {
    throw new AppError('Forbidden: shop is outside your assigned scope', 403);
  }
}

// GET /api/inventory/queries
const getQueries = asyncHandler(async (req, res) => {
  const scope = buildInventoryScope(req.user);
  const filter = {};
  applyScopeFilter(filter, scope);

  if (req.query.shop_id) {
    if (!scope.all && !isShopAllowed(scope, req.query.shop_id)) {
      return sendSuccess(res, 'Inventory queries fetched successfully', {
        count: 0,
        queries: [],
      });
    }
    filter.shop_id = req.query.shop_id;
  }
  if (req.query.status) filter.status = req.query.status;
  if (req.query.item_id) {
    const itemFilter = { _id: req.query.item_id };
    applyScopeFilter(itemFilter, scope);
    const scopedItem = await InventoryItem.findOne(itemFilter).select('_id');
    if (!scopedItem) {
      return sendSuccess(res, 'Inventory queries fetched successfully', {
        count: 0,
        queries: [],
      });
    }
    filter.item_id = req.query.item_id;
  }

  const queries = await InventoryQuery.find(filter)
    .populate('item_id', 'item_name status')
    .populate('shop_id', 'name')
    .populate('reported_by', 'name email')
    .populate('resolved_by', 'name email')
    .sort({ createdAt: -1 });

  return sendSuccess(res, 'Inventory queries fetched successfully', {
    count: queries.length,
    queries,
  });
});

// GET /api/inventory/queries/:id
const getQuery = asyncHandler(async (req, res) => {
  const scope = buildInventoryScope(req.user);
  const filter = { _id: req.params.id };
  applyScopeFilter(filter, scope);

  const query = await InventoryQuery.findOne(filter)
    .populate('item_id', 'item_name status')
    .populate('shop_id', 'name')
    .populate('reported_by', 'name email')
    .populate('resolved_by', 'name email');

  if (!query) throw new AppError('Query not found', 404);
  return sendSuccess(res, 'Inventory query fetched successfully', { query });
});

// POST /api/inventory/queries
// Creates the query ticket + auto-sets item status to 'Damaged'
const createQuery = asyncHandler(async (req, res) => {
  const { item_id, shop_id, issue_note } = req.body;
  const scope = buildInventoryScope(req.user);

    // Verify item exists
  const item = await InventoryItem.findById(item_id);
  if (!item) throw new AppError('Inventory item not found', 404);
  assertShopAllowed(scope, item.shop_id);

  if (shop_id && item.shop_id.toString() !== shop_id.toString()) {
    throw new AppError('shop_id must match the item shop', 400);
  }

    // Create the query (ticket)
  const effectiveShopId = shop_id || item.shop_id;
  assertShopAllowed(scope, effectiveShopId);
  const query = await InventoryQuery.create({
    item_id,
    shop_id: effectiveShopId,
    reported_by: req.user._id,
    issue_note,
    status: 'Open',
  });

    // ── Auto-sync: set item status to 'Damaged' ──
  item.status = 'Damaged';
  await item.save();

  const populated = await query.populate([
    { path: 'item_id', select: 'item_name status' },
    { path: 'shop_id', select: 'name' },
    { path: 'reported_by', select: 'name email' },
  ]);

  return sendSuccess(res, 'Query opened and item marked as Damaged', {
    query: populated,
  }, 201);
});

// PUT /api/inventory/queries/:id/close
// Closes the query + auto-reverts item status to 'Good'
const closeQuery = asyncHandler(async (req, res) => {
  const { repair_cost, resolve_note } = req.body;
  const scope = buildInventoryScope(req.user);

  const query = await InventoryQuery.findById(req.params.id);
  if (!query) throw new AppError('Query not found', 404);
  assertShopAllowed(scope, query.shop_id);

  if (query.status === 'Closed') {
    throw new AppError('Query is already closed', 400);
  }

    // Update the query
  query.status = 'Closed';
  query.repair_cost = repair_cost ?? null;
  query.resolve_note = resolve_note ?? null;
  query.resolved_by = req.user._id;
  query.resolved_at = new Date();
  await query.save();

    // ── Auto-sync: revert item status to 'Good' ──
  await InventoryItem.findByIdAndUpdate(query.item_id, { status: 'Good' });

  const populated = await query.populate([
    { path: 'item_id', select: 'item_name status' },
    { path: 'resolved_by', select: 'name email' },
  ]);

  return sendSuccess(res, 'Query closed and item status reverted to Good', {
    query: populated,
  });
});

module.exports = { getQueries, getQuery, createQuery, closeQuery };

const RequestMetric = require('../models/RequestMetric');
const ErrorLog = require('../models/ErrorLog');
const asyncHandler = require('../utils/asyncHandler');
const { sendSuccess } = require('../utils/response');

const getDays = (value) => {
  const parsed = Number.parseInt(value, 10);
  if (Number.isNaN(parsed)) return 7;
  return Math.max(1, Math.min(parsed, 90));
};

const sinceDate = (days) => {
  const now = new Date();
  now.setUTCHours(0, 0, 0, 0);
  now.setUTCDate(now.getUTCDate() - (days - 1));
  return now;
};

const getOverview = asyncHandler(async (req, res) => {
  const days = getDays(req.query.days);
  const since = sinceDate(days);

  const [totals, statusBreakdown, topErrorRoutes, daily, recentErrors] = await Promise.all([
    RequestMetric.aggregate([
      { $match: { day: { $gte: since } } },
      {
        $group: {
          _id: null,
          requests: { $sum: '$count' },
          errors: {
            $sum: {
              $cond: [{ $gte: ['$status_code', 400] }, '$count', 0],
            },
          },
          total_latency_ms: { $sum: '$total_response_ms' },
        },
      },
    ]),
    RequestMetric.aggregate([
      { $match: { day: { $gte: since } } },
      { $group: { _id: '$status_code', count: { $sum: '$count' } } },
      { $sort: { _id: 1 } },
    ]),
    RequestMetric.aggregate([
      { $match: { day: { $gte: since }, status_code: { $gte: 400 } } },
      {
        $group: {
          _id: { route: '$route', method: '$method' },
          count: { $sum: '$count' },
        },
      },
      { $sort: { count: -1 } },
      { $limit: 10 },
    ]),
    RequestMetric.aggregate([
      { $match: { day: { $gte: since } } },
      {
        $group: {
          _id: '$day',
          requests: { $sum: '$count' },
          errors: {
            $sum: {
              $cond: [{ $gte: ['$status_code', 400] }, '$count', 0],
            },
          },
        },
      },
      { $sort: { _id: 1 } },
    ]),
    ErrorLog.find({ createdAt: { $gte: since } })
      .sort({ createdAt: -1 })
      .limit(20)
      .select('status_code message path method createdAt'),
  ]);

  const totalRequests = totals[0]?.requests || 0;
  const totalErrors = totals[0]?.errors || 0;
  const avgResponseMs = totalRequests > 0
    ? Number((totals[0].total_latency_ms / totalRequests).toFixed(2))
    : 0;

  return sendSuccess(res, 'Observability overview fetched successfully', {
    range_days: days,
    totals: {
      requests: totalRequests,
      errors: totalErrors,
      error_rate_pct: totalRequests > 0
        ? Number(((totalErrors / totalRequests) * 100).toFixed(2))
        : 0,
      avg_response_ms: avgResponseMs,
    },
    status_breakdown: statusBreakdown.map((row) => ({
      status_code: row._id,
      count: row.count,
    })),
    top_error_routes: topErrorRoutes.map((row) => ({
      route: row._id.route,
      method: row._id.method,
      count: row.count,
    })),
    daily: daily.map((row) => ({
      day: row._id,
      requests: row.requests,
      errors: row.errors,
    })),
    recent_errors: recentErrors,
  });
});

const getErrorLogs = asyncHandler(async (req, res) => {
  const days = getDays(req.query.days);
  const limit = Math.max(1, Math.min(Number.parseInt(req.query.limit, 10) || 50, 200));
  const since = sinceDate(days);

  const filter = { createdAt: { $gte: since } };
  if (req.query.status_code) {
    filter.status_code = Number.parseInt(req.query.status_code, 10);
  }
  if (req.query.path) {
    filter.path = { $regex: req.query.path, $options: 'i' };
  }

  const logs = await ErrorLog.find(filter)
    .sort({ createdAt: -1 })
    .limit(limit)
    .populate('user_id', 'name email');

  return sendSuccess(res, 'Error logs fetched successfully', {
    count: logs.length,
    logs,
  });
});

module.exports = {
  getOverview,
  getErrorLogs,
};

const Rota = require('../models/Rota');
const AppError = require('../utils/AppError');
const asyncHandler = require('../utils/asyncHandler');
const { sendSuccess } = require('../utils/response');

function buildDates(weekStart, days) {
  const base = new Date(weekStart);
  base.setUTCHours(0, 0, 0, 0);
  const dayOfWeek = base.getUTCDay();
  const offsetToMon = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
  base.setUTCDate(base.getUTCDate() + offsetToMon);

  return days.map((d) => {
    const date = new Date(base);
    date.setUTCDate(base.getUTCDate() + d);
    return date;
  });
}

function weekBounds(weekStart) {
  const dates = buildDates(weekStart, [0, 1, 2, 3, 4, 5, 6]);
  const start = new Date(dates[0]);
  const end = new Date(dates[6]);
  end.setUTCHours(23, 59, 59, 999);
  return { start, end };
}

const DAY_NAMES = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

const getRotas = asyncHandler(async (req, res) => {
  const filter = {};
  if (req.query.shop_id) filter.shop_id = req.query.shop_id;
  if (req.query.user_id) filter.user_id = req.query.user_id;
  if (req.query.date) filter.shift_date = new Date(req.query.date);

  const rotas = await Rota.find(filter)
    .populate('user_id', 'name email')
    .populate('shop_id', 'name')
    .sort({ shift_date: 1, start_time: 1 });

  return sendSuccess(res, 'Rota list fetched successfully', {
    count: rotas.length,
    rotas,
  });
});

const getRota = asyncHandler(async (req, res) => {
  const rota = await Rota.findById(req.params.id)
    .populate('user_id', 'name email')
    .populate('shop_id', 'name');

  if (!rota) throw new AppError('Rota not found', 404);
  return sendSuccess(res, 'Rota fetched successfully', { rota });
});

const createRota = asyncHandler(async (req, res) => {
  try {
    const rota = await Rota.create(req.body);
    const populated = await rota.populate([
      { path: 'user_id', select: 'name email' },
      { path: 'shop_id', select: 'name' },
    ]);
    return sendSuccess(res, 'Rota created successfully', { rota: populated }, 201);
  } catch (err) {
    if (err.code === 11000) {
      throw new AppError('A rota entry for this user/date/start_time already exists', 409);
    }
    throw err;
  }
});

const updateRota = asyncHandler(async (req, res) => {
  try {
    const rota = await Rota.findByIdAndUpdate(req.params.id, req.body, {
      new: true,
      runValidators: true,
    })
      .populate('user_id', 'name email')
      .populate('shop_id', 'name');

    if (!rota) throw new AppError('Rota not found', 404);
    return sendSuccess(res, 'Rota updated successfully', { rota });
  } catch (err) {
    if (err.code === 11000) {
      throw new AppError('Conflict: a rota with that user/date/start_time already exists', 409);
    }
    throw err;
  }
});

const deleteRota = asyncHandler(async (req, res) => {
  const rota = await Rota.findByIdAndDelete(req.params.id);
  if (!rota) throw new AppError('Rota not found', 404);
  return sendSuccess(res, 'Rota deleted', { rota });
});

const bulkCreate = asyncHandler(async (req, res) => {
  const { shop_id, week_start, days, assignments, replace_existing = false } = req.body;

  if (!shop_id || !week_start || !Array.isArray(days) || !Array.isArray(assignments)) {
    throw new AppError('shop_id, week_start, days[], and assignments[] are all required', 400);
  }
  if (days.some((d) => d < 0 || d > 6)) {
    throw new AppError('days values must be 0 (Mon) - 6 (Sun)', 400);
  }

  const dates = buildDates(week_start, days);
  const { start: weekStart, end: weekEnd } = weekBounds(week_start);
  const userIds = [...new Set(assignments.map((a) => a.user_id))];

  if (replace_existing) {
    await Rota.deleteMany({
      user_id: { $in: userIds },
      shift_date: { $gte: weekStart, $lte: weekEnd },
    });
  }

  const toInsert = [];
  for (const date of dates) {
    for (const assignment of assignments) {
      toInsert.push({
        user_id: assignment.user_id,
        shop_id,
        shift_date: date,
        start_time: assignment.start_time,
        end_time: assignment.end_time || undefined,
        note: assignment.note || undefined,
      });
    }
  }

  let created = 0;
  const conflicts = [];

  const result = await Rota.insertMany(toInsert, { ordered: false }).catch((err) => {
    if (err.name === 'MongoBulkWriteError' || err.code === 11000) {
      created = err.result?.nInserted ?? err.insertedDocs?.length ?? 0;
      (err.writeErrors || []).forEach((we) => {
        const doc = we.err?.op || we.op || toInsert[we.index];
        if (doc) {
          conflicts.push({
            user_id: doc.user_id,
            date: doc.shift_date,
            start_time: doc.start_time,
            reason: 'Duplicate entry (user already has this shift)',
          });
        }
      });
      return null;
    }
    throw err;
  });

  if (result) created = result.length;

  return sendSuccess(
    res,
    `${created} rota entries created, ${conflicts.length} skipped (duplicates)`,
    {
      created,
      skipped: conflicts.length,
      conflicts,
    },
    201
  );
});

const getWeekView = asyncHandler(async (req, res) => {
  const { shop_id, week_start } = req.query;
  if (!week_start) {
    throw new AppError('week_start is required (YYYY-MM-DD)', 400);
  }

  const { start, end } = weekBounds(week_start);
  const filter = { shift_date: { $gte: start, $lte: end } };
  if (shop_id) filter.shop_id = shop_id;

  const rotas = await Rota.find(filter)
    .populate('user_id', 'name email phone_num')
    .populate('shop_id', 'name')
    .sort({ shift_date: 1, start_time: 1 });

  const days = {};
  const allDates = buildDates(week_start, [0, 1, 2, 3, 4, 5, 6]);
  allDates.forEach((d, i) => {
    const label = `${DAY_NAMES[i]} ${d.getUTCDate()} ${d.toLocaleString('en-GB', { month: 'short', timeZone: 'UTC' })}`;
    days[label] = [];
  });

  rotas.forEach((r) => {
    const d = new Date(r.shift_date);
    const dow = d.getUTCDay();
    const idx = dow === 0 ? 6 : dow - 1;
    const label = `${DAY_NAMES[idx]} ${d.getUTCDate()} ${d.toLocaleString('en-GB', { month: 'short', timeZone: 'UTC' })}`;
    if (days[label] !== undefined) days[label].push(r);
  });

  return sendSuccess(res, 'Weekly rota view fetched successfully', {
    week_start: start,
    week_end: end,
    shop_id: shop_id || 'all',
    days,
  });
});

const clearWeek = asyncHandler(async (req, res) => {
  const { shop_id, week_start } = req.query;
  if (!week_start) {
    throw new AppError('week_start is required', 400);
  }

  const { start, end } = weekBounds(week_start);
  const filter = { shift_date: { $gte: start, $lte: end } };
  if (shop_id) filter.shop_id = shop_id;

  const { deletedCount } = await Rota.deleteMany(filter);
  return sendSuccess(res, `Cleared ${deletedCount} rota entries for the week`, {
    week_start: start.toISOString().slice(0, 10),
    deleted: deletedCount,
  });
});

const getDashboard = asyncHandler(async (req, res) => {
  const { week_start, shop_id, user_id } = req.query;
  if (!week_start) {
    throw new AppError('week_start is required', 400);
  }

  const { start, end } = weekBounds(week_start);
  const filter = { shift_date: { $gte: start, $lte: end } };
  if (shop_id) filter.shop_id = shop_id;
  if (user_id) filter.user_id = user_id;

  const rotas = await Rota.find(filter)
    .populate('user_id', 'name email')
    .populate('shop_id', 'name')
    .sort({ shift_date: 1, start_time: 1 });

  const shopMap = {};
  const allDates = buildDates(week_start, [0, 1, 2, 3, 4, 5, 6]);

  rotas.forEach((r) => {
    const sid = r.shop_id._id.toString();
    if (!shopMap[sid]) {
      shopMap[sid] = {
        shop: { _id: r.shop_id._id, name: r.shop_id.name },
        days: {},
      };
      allDates.forEach((d, i) => {
        const label = `${DAY_NAMES[i]} ${d.getUTCDate()} ${d.toLocaleString('en-GB', { month: 'short', timeZone: 'UTC' })}`;
        shopMap[sid].days[label] = [];
      });
    }

    const d = new Date(r.shift_date);
    const dow = d.getUTCDay();
    const idx = dow === 0 ? 6 : dow - 1;
    const label = `${DAY_NAMES[idx]} ${d.getUTCDate()} ${d.toLocaleString('en-GB', { month: 'short', timeZone: 'UTC' })}`;
    if (shopMap[sid].days[label] !== undefined) {
      shopMap[sid].days[label].push({
        rota_id: r._id,
        user: r.user_id,
        start_time: r.start_time,
        end_time: r.end_time,
        note: r.note,
      });
    }
  });

  const empMap = {};
  rotas.forEach((r) => {
    const uid = r.user_id._id.toString();
    if (!empMap[uid]) {
      empMap[uid] = {
        user: { _id: r.user_id._id, name: r.user_id.name, email: r.user_id.email },
        shifts: [],
      };
    }
    empMap[uid].shifts.push({
      rota_id: r._id,
      date: r.shift_date,
      shop: { _id: r.shop_id._id, name: r.shop_id.name },
      start_time: r.start_time,
      end_time: r.end_time,
      note: r.note,
    });
  });

  return sendSuccess(res, 'Rota dashboard fetched successfully', {
    week_start: start,
    week_end: end,
    total_shifts: rotas.length,
    by_shop: Object.values(shopMap),
    by_employee: Object.values(empMap),
  });
});

module.exports = {
  getRotas, getRota, createRota, updateRota, deleteRota,
  bulkCreate, getWeekView, clearWeek, getDashboard,
};

const Rota = require('../models/Rota');
const AppError = require('../utils/AppError');
const asyncHandler = require('../utils/asyncHandler');
const { sendSuccess } = require('../utils/response');
const { buildShopScope, isShopAllowed } = require('../middleware/shopScopeMiddleware');

function buildDates(weekStart, days) {
  const base = new Date(weekStart);
  base.setUTCHours(0, 0, 0, 0);
  const dayOfWeek = base.getUTCDay();
  const offsetToMon = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
  base.setUTCDate(base.getUTCDate() + offsetToMon);

  return days.map((d) => {
    const date = new Date(base);
    date.setUTCDate(base.getUTCDate() + d);
    return date;
  });
}

function weekBounds(weekStart) {
  const dates = buildDates(weekStart, [0, 1, 2, 3, 4, 5, 6]);
  const start = new Date(dates[0]);
  const end = new Date(dates[6]);
  end.setUTCHours(23, 59, 59, 999);
  return { start, end };
}

const DAY_NAMES = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

function buildRotaReadScope(user) {
  const permissions = user?.role_id?.permissions || {};
  if (permissions.can_manage_shops || permissions.can_manage_roles) {
    return { mode: 'all', shopScope: { all: true, ids: [] } };
  }

  if (permissions.can_view_all_staff || permissions.can_manage_inventory || permissions.can_manual_punch) {
    return { mode: 'shops', shopScope: buildShopScope(user) };
  }

  return { mode: 'self', shopScope: { all: false, ids: [] } };
}

function normalizeId(value) {
  if (!value) return null;
  if (typeof value === 'string') return value;
  if (value._id) return value._id.toString();
  return value.toString();
}

function applyScopeFilter(filter, req, scope) {
  if (scope.mode === 'self') {
    filter.user_id = req.user._id;
    return;
  }

  if (scope.mode === 'shops') {
    if (!scope.shopScope.all && scope.shopScope.ids.length === 0) {
      filter.shop_id = { $in: [] };
      return;
    }
    if (!scope.shopScope.all) {
      filter.shop_id = { $in: scope.shopScope.ids };
    }
  }
}

function buildRotaManageScope(user) {
  const permissions = user?.role_id?.permissions || {};
  if (permissions.can_manage_shops || permissions.can_manage_roles) {
    return { mode: 'all', shopScope: { all: true, ids: [] } };
  }
  if (permissions.can_manage_rotas) {
    return { mode: 'shops', shopScope: buildShopScope(user) };
  }
  return { mode: 'none', shopScope: { all: false, ids: [] } };
}

function applyManageScopeFilter(filter, scope) {
  if (scope.mode === 'all') return;
  if (!scope.shopScope.all && scope.shopScope.ids.length === 0) {
    filter.shop_id = { $in: [] };
    return;
  }
  if (!scope.shopScope.all) {
    filter.shop_id = { $in: scope.shopScope.ids };
  }
}

function assertManageShopAllowed(scope, shopId) {
  if (scope.mode === 'all') return;
  if (!isShopAllowed(scope.shopScope, shopId)) {
    throw new AppError('Forbidden: shop is outside your assigned scope', 403);
  }
}

const getRotas = asyncHandler(async (req, res) => {
  const scope = buildRotaReadScope(req.user);
  const filter = {};
  applyScopeFilter(filter, req, scope);

  if (req.query.shop_id) {
    if (scope.mode === 'shops' && !scope.shopScope.all && !isShopAllowed(scope.shopScope, req.query.shop_id)) {
      return sendSuccess(res, 'Rota list fetched successfully', { count: 0, rotas: [] });
    }
    filter.shop_id = req.query.shop_id;
  }
  if (req.query.user_id && scope.mode !== 'self') filter.user_id = req.query.user_id;
  if (req.query.date) filter.shift_date = new Date(req.query.date);

  const rotas = await Rota.find(filter)
    .populate('user_id', 'name email')
    .populate('shop_id', 'name')
    .sort({ shift_date: 1, start_time: 1 });

  return sendSuccess(res, 'Rota list fetched successfully', {
    count: rotas.length,
    rotas,
  });
});

const getRota = asyncHandler(async (req, res) => {
  const scope = buildRotaReadScope(req.user);
  const filter = { _id: req.params.id };
  applyScopeFilter(filter, req, scope);

  const rota = await Rota.findOne(filter)
    .populate('user_id', 'name email')
    .populate('shop_id', 'name');

  if (!rota) throw new AppError('Rota not found', 404);
  return sendSuccess(res, 'Rota fetched successfully', { rota });
});

const createRota = asyncHandler(async (req, res) => {
  const scope = buildRotaManageScope(req.user);
  assertManageShopAllowed(scope, req.body.shop_id);

  try {
    const rota = await Rota.create(req.body);
    const populated = await rota.populate([
      { path: 'user_id', select: 'name email' },
      { path: 'shop_id', select: 'name' },
    ]);
    return sendSuccess(res, 'Rota created successfully', { rota: populated }, 201);
  } catch (err) {
    if (err.code === 11000) {
      throw new AppError('A rota entry for this user/date/start_time already exists', 409);
    }
    throw err;
  }
});

const updateRota = asyncHandler(async (req, res) => {
  const scope = buildRotaManageScope(req.user);
  const existing = await Rota.findById(req.params.id);
  if (!existing) throw new AppError('Rota not found', 404);
  assertManageShopAllowed(scope, existing.shop_id);
  if (req.body.shop_id) assertManageShopAllowed(scope, req.body.shop_id);

  try {
    const rota = await Rota.findByIdAndUpdate(req.params.id, req.body, {
      new: true,
      runValidators: true,
    })
      .populate('user_id', 'name email')
      .populate('shop_id', 'name');

    if (!rota) throw new AppError('Rota not found', 404);
    return sendSuccess(res, 'Rota updated successfully', { rota });
  } catch (err) {
    if (err.code === 11000) {
      throw new AppError('Conflict: a rota with that user/date/start_time already exists', 409);
    }
    throw err;
  }
});

const deleteRota = asyncHandler(async (req, res) => {
  const scope = buildRotaManageScope(req.user);
  const existing = await Rota.findById(req.params.id);
  if (!existing) throw new AppError('Rota not found', 404);
  assertManageShopAllowed(scope, existing.shop_id);

  const rota = await Rota.findByIdAndDelete(req.params.id);
  if (!rota) throw new AppError('Rota not found', 404);
  return sendSuccess(res, 'Rota deleted', { rota });
});

const bulkCreate = asyncHandler(async (req, res) => {
