  }

  const rotas = await Rota.find(filter)
    .populate('user_id', 'name email')
    .populate('shop_id', 'name')
    .sort({ shift_date: 1, start_time: 1 });

  const shopMap = {};
  const allDates = buildDates(week_start, [0, 1, 2, 3, 4, 5, 6]);

  rotas.forEach((r) => {
    const sid = r.shop_id._id.toString();
    if (!shopMap[sid]) {
      shopMap[sid] = {
        shop: { _id: r.shop_id._id, name: r.shop_id.name },
        days: {},
      };
      allDates.forEach((d, i) => {
        const label = `${DAY_NAMES[i]} ${d.getUTCDate()} ${d.toLocaleString('en-GB', { month: 'short', timeZone: 'UTC' })}`;
        shopMap[sid].days[label] = [];
      });
    }

    const d = new Date(r.shift_date);
    const dow = d.getUTCDay();
    const idx = dow === 0 ? 6 : dow - 1;
    const label = `${DAY_NAMES[idx]} ${d.getUTCDate()} ${d.toLocaleString('en-GB', { month: 'short', timeZone: 'UTC' })}`;
    if (shopMap[sid].days[label] !== undefined) {
      shopMap[sid].days[label].push({
        rota_id: r._id,
        user: r.user_id,
        start_time: r.start_time,
        end_time: r.end_time,
        note: r.note,
      });
    }
  });

  const empMap = {};
  rotas.forEach((r) => {
    const uid = r.user_id._id.toString();
    if (!empMap[uid]) {
      empMap[uid] = {
        user: { _id: r.user_id._id, name: r.user_id.name, email: r.user_id.email },
        shifts: [],
      };
    }
    empMap[uid].shifts.push({
      rota_id: r._id,
      date: r.shift_date,
      shop: { _id: r.shop_id._id, name: r.shop_id.name },
      start_time: r.start_time,
      end_time: r.end_time,
      note: r.note,
    });
  });

  return sendSuccess(res, 'Rota dashboard fetched successfully', {
    week_start: start,
    week_end: end,
    total_shifts: rotas.length,
    by_shop: Object.values(shopMap),
    by_employee: Object.values(empMap),
  });
});

module.exports = {
  getRotas, getRota, createRota, updateRota, deleteRota,
  bulkCreate, getWeekView, clearWeek, getDashboard,
};

const { sendResponse } = require('../utils/response');
const AppError = require('../utils/AppError');

const notFoundHandler = (req, res, next) => {
  next(new AppError(`Route ${req.originalUrl} not found`, 404));
};

const globalErrorHandler = (err, req, res, _next) => {
  let statusCode = err.statusCode || 500;
  let message = err.message || 'Internal server error';
  let data = err.data || {};

  if (err.name === 'CastError') {
    statusCode = 400;
    message = `Invalid ${err.path}: ${err.value}`;
  } else if (err.name === 'ValidationError') {
    statusCode = 400;
    message = 'Validation failed';
    data = {
      errors: Object.values(err.errors || {}).map((e) => ({
        field: e.path,
        message: e.message,
      })),
    };
  } else if (err.code === 11000) {
    statusCode = 409;
    message = 'Duplicate value violates unique constraint';
    data = { duplicate: err.keyValue || {} };
  } else if (err.name === 'JsonWebTokenError' || err.name === 'TokenExpiredError') {
    statusCode = 401;
    message = 'Token invalid or expired';
  }

  if (statusCode >= 500) {
    console.error(err);
    if (!(err instanceof AppError)) {
      message = 'Internal server error';
      data = {};
    }
  }

  return sendResponse(res, statusCode, message, data);
};

module.exports = {
  notFoundHandler,
  globalErrorHandler,
};

const { sendResponse } = require('../utils/response');
const AppError = require('../utils/AppError');
const { recordErrorLog } = require('../utils/observability');

const notFoundHandler = (req, res, next) => {
  next(new AppError(`Route ${req.originalUrl} not found`, 404));
};

const globalErrorHandler = (err, req, res, _next) => {
  let statusCode = err.statusCode || 500;
  let message = err.message || 'Internal server error';
  let data = err.data || {};

  if (err.name === 'CastError') {
    statusCode = 400;
    message = `Invalid ${err.path}: ${err.value}`;
  } else if (err.name === 'ValidationError') {
    statusCode = 400;
    message = 'Validation failed';
    data = {
      errors: Object.values(err.errors || {}).map((e) => ({
        field: e.path,
        message: e.message,
      })),
    };
  } else if (err.code === 11000) {
    statusCode = 409;
    message = 'Duplicate value violates unique constraint';
    data = { duplicate: err.keyValue || {} };
  } else if (err.name === 'JsonWebTokenError' || err.name === 'TokenExpiredError') {
    statusCode = 401;
    message = 'Token invalid or expired';
  }

  if (statusCode >= 500) {
    console.error(err);
    if (!(err instanceof AppError)) {
      message = 'Internal server error';
      data = {};
    }
  }

  recordErrorLog({
    req,
    statusCode,
    message,
    stack: statusCode >= 500 ? err.stack : null,
    meta: {
      error_name: err.name,
      original_message: err.message,
    },
  });
  res.locals.errorLogged = true;

  return sendResponse(res, statusCode, message, data);
};

module.exports = {
  notFoundHandler,
  globalErrorHandler,
};

/**
 * Permission middleware factory.
 * Usage: requirePermission('can_create_users')
 * Reads the permissions object from the user's role (populated by authMiddleware).
 */
const AppError = require('../utils/AppError');

const requirePermission = (permission) => {
  return (req, res, next) => {
    const role = req.user && req.user.role_id;
    if (!role || !role.permissions || !role.permissions[permission]) {
      return next(new AppError(`Forbidden: requires '${permission}' permission`, 403));
    }
    next();
  };
};

module.exports = { requirePermission };

/**
 * Permission middleware factory.
 * Usage: requirePermission('can_create_users')
 * Reads the permissions object from the user's role (populated by authMiddleware).
 */
const AppError = require('../utils/AppError');

const requirePermission = (permission) => {
  return (req, res, next) => {
    const role = req.user && req.user.role_id;
    if (!role || !role.permissions || !role.permissions[permission]) {
      return next(new AppError(`Forbidden: requires '${permission}' permission`, 403));
    }
    next();
  };
};

const requireRoot = () => {
  return (req, res, next) => {
    const roleName = req.user?.role_id?.role_name;
    if (roleName !== 'Root') {
      return next(new AppError('Forbidden: root access required', 403));
    }
    next();
  };
};

module.exports = { requirePermission, requireRoot };

const { recordRequestMetric, recordErrorLog } = require('../utils/observability');

const shouldSkipPath = (path) => {
  if (!path) return false;
  return path.startsWith('/api-docs');
};

const requestAnalytics = (req, res, next) => {
  const startedAt = process.hrtime.bigint();

  res.on('finish', () => {
    if (shouldSkipPath(req.originalUrl || req.url)) return;

    const endedAt = process.hrtime.bigint();
    const responseMs = Number(endedAt - startedAt) / 1e6;
    const statusCode = res.statusCode;

    recordRequestMetric({ req, statusCode, responseMs });

    if (statusCode >= 400 && !res.locals.errorLogged) {
      recordErrorLog({
        req,
        statusCode,
        message: `HTTP ${statusCode} response`,
      });
    }
  });

  next();
};

module.exports = { requestAnalytics };

const unique = (ids) => [...new Set(ids)];

const toId = (value) => {
  if (!value) return null;
  if (typeof value === 'string') return value;
  if (value._id) return value._id.toString();
  return value.toString();
};

const resolveAllowedShopIds = (user) => {
  const assigned = Array.isArray(user?.assigned_shop_ids)
    ? user.assigned_shop_ids.map(toId).filter(Boolean)
    : [];
  const primary = toId(user?.shop_id);
  return unique(primary ? [...assigned, primary] : assigned);
};

const canAccessAllShops = (user) => {
  const permissions = user?.role_id?.permissions || {};
  return Boolean(permissions.can_manage_shops || permissions.can_manage_roles);
};

const buildShopScope = (user) => ({
  all: canAccessAllShops(user),
  ids: resolveAllowedShopIds(user),
});

const isShopAllowed = (shopScope, shopId) => {
  if (!shopId) return false;
  if (shopScope?.all) return true;
  const id = toId(shopId);
  return Boolean(id && shopScope?.ids?.includes(id));
};

module.exports = {
  resolveAllowedShopIds,
  canAccessAllShops,
  buildShopScope,
  isShopAllowed,
};

