      trim: true,
    },
    phone_code: {
      type: String,
      trim: true, // e.g. "+44"
    },
    phone_num: {
      type: String,
      trim: true,
    },
    password_hash: {
      type: String,
      required: true,
      select: false, // never returned in queries by default
    },
    role_id: {
      type: mongoose.Schema.Types.ObjectId,
      ref: 'Role',
      required: [true, 'Role is required'],
    },
    device_id: {
      type: String,
      trim: true,
      default: null,
    },
    shop_id: {
      type: mongoose.Schema.Types.ObjectId,
      ref: 'Shop',
      default: null,
    },
