      .set('Authorization', `Bearer ${managerLogin.token}`)
      .send({ resolve_note: 'Duplicate close' });
    expectEnvelope(closeAgainRes, 400);
  });

  it('INV-009: manager list is limited to assigned shops', async () => {
    await User.findByIdAndUpdate(fixtures.users.managerUser._id, {
      assigned_shop_ids: [fixtures.shops.mainShop._id],
      shop_id: fixtures.shops.mainShop._id,
    });

    const managerLogin = await login('manager@org.com', 'Manager@1234');
    const res = await request(app)
      .get('/api/inventory/items')
      .set('Authorization', `Bearer ${managerLogin.token}`);

    expectEnvelope(res, 200);
    expect(res.body.data.count).toBe(1);
    expect(res.body.data.items[0].shop_id._id).toBe(fixtures.shops.mainShop._id.toString());
  });

  it('INV-010: manager cannot read or create items outside assigned shops', async () => {
    await User.findByIdAndUpdate(fixtures.users.managerUser._id, {
      assigned_shop_ids: [fixtures.shops.mainShop._id],
      shop_id: fixtures.shops.mainShop._id,
    });

    const managerLogin = await login('manager@org.com', 'Manager@1234');
    const eastItem = fixtures.inventoryItems[1];

    const readRes = await request(app)
      .get(`/api/inventory/items/${eastItem._id}`)
      .set('Authorization', `Bearer ${managerLogin.token}`);
    expectEnvelope(readRes, 404);

    const createRes = await request(app)
      .post('/api/inventory/items')
      .set('Authorization', `Bearer ${managerLogin.token}`)
      .send({
        shop_id: fixtures.shops.eastShop._id.toString(),
        item_name: 'Unauthorized Scanner',
        status: 'Good',
      });
    expectEnvelope(createRes, 403);
  });

  it('QRY-008: manager cannot open or close queries outside assigned shops', async () => {
    await User.findByIdAndUpdate(fixtures.users.managerUser._id, {
      assigned_shop_ids: [fixtures.shops.mainShop._id],
      shop_id: fixtures.shops.mainShop._id,
    });

    const managerLogin = await login('manager@org.com', 'Manager@1234');
    const eastItem = fixtures.inventoryItems[1];

    const openBlocked = await request(app)
      .post('/api/inventory/queries')
      .set('Authorization', `Bearer ${managerLogin.token}`)
      .send({ item_id: eastItem._id.toString(), issue_note: 'Out of scope item' });
    expectEnvelope(openBlocked, 403);

    const adminLogin = await login('admin@org.com', 'Admin@1234');
    const adminOpen = await request(app)
      .post('/api/inventory/queries')
      .set('Authorization', `Bearer ${adminLogin.token}`)
      .send({ item_id: eastItem._id.toString(), issue_note: 'Admin opened east query' });
    expectEnvelope(adminOpen, 201);

    const queryId = adminOpen.body.data.query._id;
    const closeBlocked = await request(app)
      .put(`/api/inventory/queries/${queryId}/close`)
      .set('Authorization', `Bearer ${managerLogin.token}`)
      .send({ resolve_note: 'Manager out of scope close attempt' });
    expectEnvelope(closeBlocked, 403);

    const queryStillOpen = await InventoryQuery.findById(queryId);
    expect(queryStillOpen.status).toBe('Open');
  });
});

const request = require('supertest');
const app = require('../../src/app');
const { expectEnvelope } = require('../helpers/assertions');
const { login } = require('../helpers/auth');
const { seedTestData } = require('../helpers/seedTestData');
const {
  connectSandboxDb,
  clearSandboxDb,
  disconnectSandboxDb,
} = require('../setup/testDb');

const delay = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

describe('Observability dashboard integration', () => {
  beforeAll(async () => {
    await connectSandboxDb();
  });

  beforeEach(async () => {
    await clearSandboxDb();
    await seedTestData();
  });

  afterAll(async () => {
    await disconnectSandboxDb();
  });

  it('allows root to view analytics overview with request and error totals', async () => {
    const rootLogin = await login('root@org.com', 'Root@1234');

    await request(app)
      .post('/api/auth/login')
      .send({ email: 'root@org.com', password: 'WrongPassword' });

    await request(app)
      .get('/api/users')
      .set('Authorization', `Bearer ${rootLogin.token}`);

    await delay(120);

    const res = await request(app)
      .get('/api/observability/overview?days=7')
      .set('Authorization', `Bearer ${rootLogin.token}`);

    expectEnvelope(res, 200);
    expect(res.body.data.totals.requests).toBeGreaterThan(0);
    expect(res.body.data.totals.errors).toBeGreaterThan(0);
    expect(Array.isArray(res.body.data.status_breakdown)).toBe(true);
  });

  it('allows root to view error log list', async () => {
    const rootLogin = await login('root@org.com', 'Root@1234');

    await request(app)
      .post('/api/auth/login')
      .send({ email: 'root@org.com' });

    await delay(120);

    const res = await request(app)
      .get('/api/observability/errors?limit=20')
      .set('Authorization', `Bearer ${rootLogin.token}`);

    expectEnvelope(res, 200);
    expect(res.body.data.count).toBeGreaterThan(0);
    expect(Array.isArray(res.body.data.logs)).toBe(true);
  });

  it('blocks non-root users from observability endpoints', async () => {
    const adminLogin = await login('admin@org.com', 'Admin@1234');

    const overviewRes = await request(app)
      .get('/api/observability/overview')
      .set('Authorization', `Bearer ${adminLogin.token}`);
    expectEnvelope(overviewRes, 403);

    const errorsRes = await request(app)
      .get('/api/observability/errors')
      .set('Authorization', `Bearer ${adminLogin.token}`);
    expectEnvelope(errorsRes, 403);
  });
});

const request = require('supertest');
const app = require('../../src/app');
const { expectEnvelope } = require('../helpers/assertions');
const { login } = require('../helpers/auth');
const { seedTestData } = require('../helpers/seedTestData');
const {
  connectSandboxDb,
  clearSandboxDb,
  disconnectSandboxDb,
} = require('../setup/testDb');

describe('Rota module integration', () => {
  let fixtures;

  beforeAll(async () => {
    await connectSandboxDb();
  });

  beforeEach(async () => {
    await clearSandboxDb();
    fixtures = await seedTestData();
  });

  afterAll(async () => {
    await disconnectSandboxDb();
  });

  it('ROTA-006: manager creates bulk rota successfully', async () => {
    const managerLogin = await login('manager@org.com', 'Manager@1234');

    const res = await request(app)
      .post('/api/rotas/bulk')
      .set('Authorization', `Bearer ${managerLogin.token}`)
      .send({
        shop_id: fixtures.shops.mainShop._id.toString(),
        week_start: '2026-03-16',
        days: [0, 1],
        assignments: [
          {
            user_id: fixtures.users.staffUser._id.toString(),
            start_time: '08:00',
            end_time: '16:00',
          },
        ],
      });

    expectEnvelope(res, 201);
    expect(res.body.data.created).toBeGreaterThan(0);
  });

  it('ROTA-001 and ROTA-002: lists rotas and fetches a single rota', async () => {
    const managerLogin = await login('manager@org.com', 'Manager@1234');
    const listRes = await request(app)
      .get('/api/rotas')
      .set('Authorization', `Bearer ${managerLogin.token}`);
    expectEnvelope(listRes, 200);
    expect(Array.isArray(listRes.body.data.rotas)).toBe(true);

    const rotaId = listRes.body.data.rotas[0]._id;
    const singleRes = await request(app)
      .get(`/api/rotas/${rotaId}`)
      .set('Authorization', `Bearer ${managerLogin.token}`);
    expectEnvelope(singleRes, 200);
  });

  it('ROTA-003 and ROTA-005: allows manager create and blocks staff create', async () => {
    const managerLogin = await login('manager@org.com', 'Manager@1234');
